// Extract message data from Telegram
const update = $input.first().json;
let userId, messageText, chatId, messageType, fileInfo, callbackData, messageId;

if (update.callback_query) {
  // Inline button pressed
  userId = update.callback_query.from.id;
  chatId = update.callback_query.message.chat.id;
  callbackData = update.callback_query.data;
  messageId = update.callback_query.message.message_id;
  messageText = callbackData; // Treat callback as message
  messageType = 'callback';
} else if (update.message) {
  userId = update.message.from.id;
  chatId = update.message.chat.id;
  messageId = update.message.message_id;
  messageType = 'text';

  if (update.message.document) {
    messageType = 'file';
    fileInfo = {
      file_id: update.message.document.file_id,
      file_name: update.message.document.file_name,
      mime_type: update.message.document.mime_type,
      file_size: update.message.document.file_size
    };
    messageText = update.message.caption || 'file_upload';
  } else {
    messageText = update.message.text || '';
  }
} else {
  return [];
}

return [{
  json: {
    telegram_user_id: userId,
    chat_id: chatId,
    message_text: messageText,
    message_type: messageType,
    message_id: messageId,
    file_info: fileInfo || null,
    callback_data: callbackData || null,
    timestamp: new Date().toISOString()
  }
}];

// Rate limit check: max 30 messages per hour per user
const userId = $('Check User Auth').item.json.id;
const messageData = $('Extract Message Data').item.json;

// Store user context for downstream nodes
return [{
  json: {
    user_id: userId,
    telegram_user_id: messageData.telegram_user_id,
    chat_id: messageData.chat_id,
    message_text: messageData.message_text,
    message_type: messageData.message_type,
    message_id: messageData.message_id,
    file_info: messageData.file_info,
    callback_data: messageData.callback_data,
    user_settings: $('Check User Auth').item.json.settings,
    is_kite_provider: $('Check User Auth').item.json.is_kite_provider,
    alerts_chat_id: $('Check User Auth').item.json.alerts_chat_id,
    commands_chat_id: $('Check User Auth').item.json.commands_chat_id,
    private_chat_id: $('Check User Auth').item.json.private_chat_id,
    display_name: $('Check User Auth').item.json.display_name
  }
}];

// Parse Claude's response into structured data
const response = $input.first().json;
let parsed;

try {
  const text = response.content[0].text;
  // Clean up: remove markdown code fences if present
  const clean = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  parsed = {
    intent: 'unknown',
    raw_query: $('Prepare User Context').item.json.message_text,
    parse_error: e.message
  };
}

// Merge with user context
const ctx = $('Prepare User Context').item.json;

return [{
  json: {
    ...ctx,
    intent: parsed.intent,
    symbol: parsed.symbol ? parsed.symbol.toUpperCase().replace(/[^A-Z0-9&-]/g, '') : null,
    quantity: parsed.quantity ? parseInt(parsed.quantity) : null,
    price: parsed.price ? parseFloat(parsed.price) : null,
    lower_bound: parsed.lower_bound ? parseFloat(parsed.lower_bound) : null,
    upper_bound: parsed.upper_bound ? parseFloat(parsed.upper_bound) : null,
    request_token: parsed.request_token || null,
    raw_query: parsed.raw_query || null
  }
}];

// Fetch live prices for portfolio from Kite API
const holdings = $input.all().map(i => i.json);

if (holdings.length === 0) {
  return [{ json: { message: '📭 *No holdings found*\n\nStart by logging a trade:\n"buy RELIANCE 10 at 2850"', holdings: [] } }];
}

// Build Kite quote request
const symbols = holdings.map(h => `NSE:${h.symbol}`);
const queryParams = symbols.map(s => `i=${s}`).join('&');

// Get Kite provider credentials
// NOTE: In production, fetch encrypted token from DB and decrypt
const kiteApiKey = $env.KITE_API_KEY_USER1;
const kiteToken = $env.KITE_ACCESS_TOKEN; // Set by WF6

let quotes = {};
try {
  const response = await fetch(
    `https://api.kite.trade/quote?${queryParams}`,
    {
      headers: {
        'X-Kite-Version': '3',
        'Authorization': `token ${kiteApiKey}:${kiteToken}`
      }
    }
  );
  const data = await response.json();
  quotes = data.data || {};
} catch (e) {
  // Kite API failed — show portfolio without live prices
}

// Build portfolio message
let msg = '📊 *Your Portfolio*\n\n';
let totalInvested = 0, totalCurrent = 0;

for (const h of holdings) {
  const key = `NSE:${h.symbol}`;
  const ltp = quotes[key]?.last_price || null;
  const invested = h.net_quantity * h.avg_buy_price;
  totalInvested += invested;

  if (ltp) {
    const current = h.net_quantity * ltp;
    totalCurrent += current;
    const pnl = current - invested;
    const pnlPct = ((pnl / invested) * 100).toFixed(1);
    const emoji = pnl >= 0 ? '🟢' : '🔴';
    msg += `${emoji} *${h.symbol}*\n`;
    msg += `   ${h.net_quantity} × ₹${h.avg_buy_price} → ₹${ltp}\n`;
    msg += `   P&L: ₹${Math.round(pnl).toLocaleString()} (${pnlPct}%)\n\n`;
  } else {
    totalCurrent += invested;
    msg += `⚪ *${h.symbol}*\n`;
    msg += `   ${h.net_quantity} × ₹${h.avg_buy_price} (price unavailable)\n\n`;
  }
}

const totalPnl = totalCurrent - totalInvested;
const totalPnlPct = totalInvested > 0 ? ((totalPnl / totalInvested) * 100).toFixed(1) : '0.0';
const totalEmoji = totalPnl >= 0 ? '📈' : '📉';

msg += `━━━━━━━━━━━━━━━━━━\n`;
msg += `${totalEmoji} *Total P&L: ₹${Math.round(totalPnl).toLocaleString()} (${totalPnlPct}%)*\n`;
msg += `💰 Invested: ₹${Math.round(totalInvested).toLocaleString()}\n`;
msg += `📊 Current: ₹${Math.round(totalCurrent).toLocaleString()}`;

return [{ json: { message: msg } }];

// Handle CSV/XLS file upload for trade import
const ctx = $('Prepare User Context').item.json;
const fileInfo = ctx.file_info;

if (!fileInfo) {
  return [{ json: { message: '❌ No file detected. Please send a CSV or XLSX file.' } }];
}

const fileName = fileInfo.file_name.toLowerCase();
if (!fileName.endsWith('.csv') && !fileName.endsWith('.xlsx') && !fileName.endsWith('.xls')) {
  return [{ json: { message: '❌ Unsupported file type. Please send a .csv or .xlsx file.\n\nCSV format:\n```\nSymbol,Type,Quantity,Price,Date\nRELIANCE,BUY,10,2850,2026-02-15\n```' } }];
}

// Return file info for download in next node
return [{
  json: {
    file_id: fileInfo.file_id,
    file_name: fileInfo.file_name,
    user_id: ctx.user_id,
    chat_id: ctx.chat_id
  }
}];

const alerts = $input.all().map(i => i.json);
const chatId = $('Route by Intent').first().json.chat_id;

if (alerts.length === 0) {
  return [{ json: { chat_id: chatId, message: '📭 *No active alerts*\n\nSet one with:\n`alert RELIANCE 2800-2950`' } }];
}

let msg = '🔔 *Your Active Alerts*\n\n';
for (const a of alerts) {
  const bounds = [];
  if (a.lower_bound) bounds.push(`⬇️ ₹${a.lower_bound}`);
  if (a.upper_bound) bounds.push(`⬆️ ₹${a.upper_bound}`);
  const status = a.status === 'cooldown' ? ' _(cooldown)_' : '';
  msg += `• *${a.symbol}* — ${bounds.join(' / ')}${status}\n`;
}
msg += `\n_${alerts.length} alert(s) active_\n\nCancel with: \`cancel alert SYMBOL\``;

return [{ json: { chat_id: chatId, message: msg } }];

const symbol = $json.symbol;
const userId = $json.user_id;
const chatId = $json.chat_id;

if (!symbol) {
  return [{ json: { chat_id: chatId, query: null, message: '❌ Please specify which alert to cancel:\n`cancel alert RELIANCE`' } }];
}

return [{ json: { chat_id: chatId, user_id: userId, symbol: symbol, query: `UPDATE alerts SET status = 'cancelled' WHERE user_id = ${userId} AND symbol = '${symbol}' AND status = 'active' RETURNING symbol` } }];
